#include <stdio.h>
int main() {
    int N, M, K, Q, A, B;
    scanf("%d %d %d", &N, &M, &K);
    int grid[N][M];
    for (int i = 0; i < N; i++) {
        for (int j = 0; j < M; j++) {
            char c;
            scanf(" %c", &c);
            grid[i][j] = (c == 'H') ? 1 : 0;
        }
    }
    int prefixSum[N + 1][M + 1];
    for (int i = 0; i <= N; i++) {
        for (int j = 0; j <= M; j++) {
            prefixSum[i][j] = 0;
        }
    }
    for (int i = 1; i <= N; i++) {
        for (int j = 1; j <= M; j++) {
            prefixSum[i][j] = prefixSum[i - 1][j] + prefixSum[i][j - 1] - prefixSum[i - 1][j - 1] + grid[i - 1][j - 1];
        }
    }
    scanf("%d", &Q);
    for (int i = 0; i < Q; i++) {
        scanf("%d %d", &A, &B);
        int count = 0;
        for (int x = 0; x <= N - A; x++) {
            for (int y = 0; y <= M - B; y++) {
                int sum = prefixSum[x + A][y + B] - prefixSum[x + A][y] - prefixSum[x][y + B] + prefixSum[x][y];
                if (sum >= K) {
                    count++;
                }
            }
        }
        printf("%d\n", count);
    }
    return 0;
}

