import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int N = sc.nextInt();
        int M = sc.nextInt();
        int K = sc.nextInt();
        int[][] grid = new int[N][M];
        for (int i = 0; i < N; i++) {
            String s = sc.next();
            for (int j = 0; j < M; j++) {
                grid[i][j] = (s.charAt(j) == 'H') ? 1 : 0;
            }
        }
        int[][] prefixSum = new int[N + 1][M + 1];
        for (int i = 1; i <= N; i++) {
            for (int j = 1; j <= M; j++) {
                prefixSum[i][j] = prefixSum[i - 1][j] + prefixSum[i][j - 1] - prefixSum[i - 1][j - 1] + grid[i - 1][j - 1];
            }
        }
        int Q = sc.nextInt();
        for (int i = 0; i < Q; i++) {
            int A = sc.nextInt();
            int B = sc.nextInt();
            int count = 0;
            for (int x = 0; x <= N - A; x++) {
                for (int y = 0; y <= M - B; y++) {
                    int sum = prefixSum[x + A][y + B] - prefixSum[x + A][y] - prefixSum[x][y + B] + prefixSum[x][y];
                    if (sum >= K) {
                        count++;
                    }
                }
            }
            System.out.println(count);
        }
    }
}

